#define SIFIVE_TEST_BASE        0x100000UL
#define SIFIVE_TEST_PASS        0x5555u

#define SBI_EXT_SRST            0x53525354L
#define SBI_SRST_RESET          0L
#define SBI_SRST_TYPE_SHUTDOWN  0L
#define SBI_SRST_REASON_NONE    0L

static inline long sbi_call(long eid, long fid, long arg0, long arg1, long arg2) {
    register long a0 asm("a0") = arg0;
    register long a1 asm("a1") = arg1;
    register long a2 asm("a2") = arg2;
    register long a6 asm("a6") = fid;
    register long a7 asm("a7") = eid;
    asm volatile ("ecall"
                  : "+r"(a0)
                  : "r"(a1), "r"(a2), "r"(a6), "r"(a7)
                  : "memory");
    return a0;
}

void arch_putchar(int ch) {
    sbi_call(1, 0, ch, 0, 0);
}

void arch_shutdown(void) {
    *(volatile uint32_t *)(uintptr_t)SIFIVE_TEST_BASE = SIFIVE_TEST_PASS;
    sbi_call(SBI_EXT_SRST, SBI_SRST_RESET,
             SBI_SRST_TYPE_SHUTDOWN, SBI_SRST_REASON_NONE, 0);
    for (;;) {
        asm volatile ("wfi");
    }
}

