#include "kernel.h"

#define UART_BASE       0x800000001fe001e0ULL
#define UART_THR        0x00
#define UART_LSR        0x05
#define UART_LSR_THRE   (1u << 5)

#define GED_REG_BASE        0x80000000100e001cULL
#define GED_SLEEP_CTL       0x00
#define GED_RESET           0x02
#define GED_SLP_TYP_S5      0x05u
#define GED_SLP_TYP_POS     2
#define GED_SLP_EN          0x20u
#define GED_RESET_VALUE     0x42u

static inline uint8_t mmio_read8(uint64_t addr) {
    return *(volatile uint8_t *)(uintptr_t)addr;
}

static inline void mmio_write8(uint64_t addr, uint8_t value) {
    *(volatile uint8_t *)(uintptr_t)addr = value;
}

void arch_putchar(int ch) {
    for (uint64_t spin = 0; spin < 1000000; spin++) {
        if ((mmio_read8(UART_BASE + UART_LSR) & UART_LSR_THRE) != 0) {
            mmio_write8(UART_BASE + UART_THR, (uint8_t)ch);
            return;
        }
    }
}

void arch_shutdown(void) {
    mmio_write8(GED_REG_BASE + GED_SLEEP_CTL,
                (uint8_t)(GED_SLP_EN | (GED_SLP_TYP_S5 << GED_SLP_TYP_POS)));
    mmio_write8(GED_REG_BASE + GED_RESET, GED_RESET_VALUE);
    for (;;) {
        asm volatile ("idle 0");
    }
}

#include "kernel.h"

static void put_raw(int ch) {
    arch_putchar(ch);
}

static void put_char(int ch) {
    if (ch == '\n') {
        put_raw('\r');
    }
    put_raw(ch);
}

static void print_u64(uint64_t value, unsigned base) {
    char buf[32];
    const char *digits = "0123456789abcdef";
    unsigned len = 0;

    if (value == 0) {
        put_char('0');
        return;
    }
    while (value != 0 && len < sizeof(buf)) {
        buf[len++] = digits[value % base];
        value /= base;
    }
    while (len > 0) {
        put_char(buf[--len]);
    }
}

void kputs(const char *s) {
    while (*s != '\0') {
        put_char(*s++);
    }
}

void kprintf(const char *fmt, ...) {
    va_list ap;
    va_start(ap, fmt);
    while (*fmt != '\0') {
        if (*fmt != '%') {
            put_char(*fmt++);
            continue;
        }
        fmt++;
        switch (*fmt) {
        case 's': {
            const char *s = va_arg(ap, const char *);
            kputs(s ? s : "(null)");
            break;
        }
        case 'c':
            put_char(va_arg(ap, int));
            break;
        case 'd': {
            int64_t v = va_arg(ap, int64_t);
            if (v < 0) {
                put_char('-');
                v = -v;
            }
            print_u64((uint64_t)v, 10);
            break;
        }
        case 'u':
            print_u64(va_arg(ap, uint64_t), 10);
            break;
        case 'x':
            print_u64(va_arg(ap, uint64_t), 16);
            break;
        case 'p':
            kputs("0x");
            print_u64((uintptr_t)va_arg(ap, void *), 16);
            break;
        case '%':
            put_char('%');
            break;
        default:
            put_char('%');
            put_char(*fmt);
            break;
        }
        if (*fmt != '\0') {
            fmt++;
        }
    }
    va_end(ap);
}

#include "kernel.h"

void *memset(void *dst, int value, size_t n) {
    unsigned char *p = (unsigned char *)dst;
    while (n-- > 0) {
        *p++ = (unsigned char)value;
    }
    return dst;
}

void *memcpy(void *dst, const void *src, size_t n) {
    unsigned char *d = (unsigned char *)dst;
    const unsigned char *s = (const unsigned char *)src;
    while (n-- > 0) {
        *d++ = *s++;
    }
    return dst;
}

int memcmp(const void *lhs, const void *rhs, size_t n) {
    const unsigned char *a = (const unsigned char *)lhs;
    const unsigned char *b = (const unsigned char *)rhs;
    while (n-- > 0) {
        if (*a != *b) {
            return (int)*a - (int)*b;
        }
        a++;
        b++;
    }
    return 0;
}

size_t strlen(const char *s) {
    size_t n = 0;
    while (s[n] != '\0') {
        n++;
    }
    return n;
}

