}

static void virtio_ack_used(void) {
    g_last_used++;
    uint32_t isr = mmio_read(VIRTIO_INTERRUPT_STATUS);
    mmio_write(VIRTIO_INTERRUPT_ACK, isr & 3);
}

int block_init(void) {
    if (mmio_read(VIRTIO_MAGIC) != 0x74726976) {
        kputs("[virtio] bad magic\n");
        return -1;
    }
    if (mmio_read(VIRTIO_DEVICE_ID) != 2) {
        kputs("[virtio] not block device\n");
        return -1;
    }

    mmio_write(VIRTIO_STATUS, 0);
    mmio_write(VIRTIO_STATUS, 1);
    mmio_write(VIRTIO_STATUS, 1 | 2);

    mmio_write(VIRTIO_HOST_FEATURES_SEL, 0);
    uint32_t features = mmio_read(VIRTIO_HOST_FEATURES);
    features &= ~(1u << 5);
    mmio_write(VIRTIO_GUEST_FEATURES_SEL, 0);
    mmio_write(VIRTIO_GUEST_FEATURES, features);

    mmio_write(VIRTIO_GUEST_PAGE_SIZE, PAGE_SIZE);
    mmio_write(VIRTIO_QUEUE_SEL, 0);
    if (mmio_read(VIRTIO_QUEUE_NUM_MAX) < QUEUE_SIZE) {
        kputs("[virtio] queue too small\n");
        return -1;
    }
    mmio_write(VIRTIO_QUEUE_NUM, QUEUE_SIZE);
    mmio_write(VIRTIO_QUEUE_ALIGN, PAGE_SIZE);
    memset(virtio_queue(), 0, sizeof(g_queue));
    mmio_write(VIRTIO_QUEUE_PFN, ((uintptr_t)&g_queue) / PAGE_SIZE);
    mmio_write(VIRTIO_STATUS, 1 | 2 | 4);
    kputs("[virtio] block ready\n");
    return 0;
}

