static int la_init_legacy_pci(uint32_t dev, uint32_t func) {
    uint32_t io_bar = LA_PCI_IO_OFFSET;

    pci_write32(dev, func, PCI_BAR0, io_bar | 1u);
    pci_write32(dev, func, PCI_BAR1, LA_PCI_MEM_BUS_BASE);
    pci_write32(dev, func, PCI_BAR4, LA_PCI_MEM_BUS_BASE + 0x1000u);
    pci_write16(dev, func, PCI_COMMAND, 0x0007);

    uint32_t bar0 = pci_read32(dev, func, PCI_BAR0);
    uint16_t command = pci_read16(dev, func, PCI_COMMAND);
    if ((bar0 & 1u) == 0) {
        return -1;
    }
    g_la_legacy_base = LA_PCI_IO_BASE + ((bar0 & ~3u) - LA_PCI_IO_OFFSET);

    vpci_write8(VIRTIO_PCI_STATUS, 0);
    vpci_write8(VIRTIO_PCI_STATUS, 1);
    vpci_write8(VIRTIO_PCI_STATUS, 1 | 2);

    uint32_t features = vpci_read32(VIRTIO_PCI_HOST_FEATURES);
    features &= ~(1u << 5);
    vpci_write32(VIRTIO_PCI_GUEST_FEATURES, features);

    vpci_write16(VIRTIO_PCI_QUEUE_SEL, 0);
    uint16_t queue_num = vpci_read16(VIRTIO_PCI_QUEUE_NUM);
    (void)command;
    if (queue_num < QUEUE_SIZE) {
        kputs("[virtio-pci] queue too small\n");
        return -1;
    }
    memset(virtio_queue(), 0, sizeof(g_queue));
    vpci_write32(VIRTIO_PCI_QUEUE_PFN, (uint32_t)(virtio_dma_addr(&g_queue) / PAGE_SIZE));
    vpci_write8(VIRTIO_PCI_STATUS, 1 | 2 | 4);

    g_avail_idx = 0;
    g_last_used = 0;
    kputs("[virtio-pci] block ready\n");
    return 0;
}

int block_init(void) {
    for (uint32_t dev = 0; dev < 32; dev++) {
        for (uint32_t func = 0; func < 8; func++) {
            uint16_t vendor = pci_read16(dev, func, 0x00);
            uint16_t device = pci_read16(dev, func, 0x02);
            if (vendor == PCI_VENDOR_REDHAT &&
                (device == PCI_DEV_VIRTIO_BLK || device == PCI_DEV_VIRTIO10_BLK)) {
                if (la_init_legacy_pci(dev, func) == 0) {
                    return 0;
                }
            }
        }
    }

    kputs("[virtio-pci] block device not found\n");
    return -1;
}

