int block_read_sector(uint64_t sector, void *buf512) {
    struct queue_mem *queue = virtio_queue();
    struct blk_req *req = (struct blk_req *)virtio_cpu_dma_ptr(&g_dma_req);
    volatile uint8_t *status = (volatile uint8_t *)virtio_cpu_dma_ptr(&g_dma_status);
    uint8_t *dma_sector = (uint8_t *)virtio_cpu_dma_ptr(g_dma_sector);

    req->type = 0;
    req->reserved = 0;
    req->sector = sector;
    *status = 0xff;

    queue->desc[0].addr = virtio_dma_addr(&g_dma_req);
    queue->desc[0].len = sizeof(g_dma_req);
    queue->desc[0].flags = 1;
    queue->desc[0].next = 1;

    queue->desc[1].addr = virtio_dma_addr(g_dma_sector);
    queue->desc[1].len = 512;
    queue->desc[1].flags = 1 | 2;
    queue->desc[1].next = 2;

    queue->desc[2].addr = virtio_dma_addr(&g_dma_status);
    queue->desc[2].len = sizeof(g_dma_status);
    queue->desc[2].flags = 2;
    queue->desc[2].next = 0;

    uint16_t slot = g_avail_idx % QUEUE_SIZE;
    queue->avail.ring[slot] = 0;
    fence_io();
    g_avail_idx++;
    queue->avail.idx = g_avail_idx;
    fence_io();
    virtio_notify_queue();

    for (uint64_t spin = 0; spin < 10000000ULL; spin++) {
        fence_io();
        if (virtio_queue_was_used()) {
            virtio_ack_used();
            if (*status != 0) {
                kprintf("[virtio] read sector %u status=%u\n", sector, (uint64_t)*status);
            }
            if (*status == 0) {
                memcpy(buf512, dma_sector, 512);
                return 0;
            }
            return -1;
        }
    }
    kprintf("[virtio] read sector %u timeout\n", sector);
    return -1;
}

int block_read(uint64_t byte_offset, void *buf, size_t len) {
    uint8_t sector_buf[512];
    uint8_t *dst = (uint8_t *)buf;
    while (len > 0) {
        uint64_t sector = byte_offset / 512;
        size_t off = (size_t)(byte_offset % 512);
        size_t n = 512 - off;
        if (n > len) {
            n = len;
        }
        if (block_read_sector(sector, sector_buf) != 0) {
            return -1;
        }
        memcpy(dst, sector_buf + off, n);
        dst += n;
        byte_offset += n;
        len -= n;
    }
    return 0;
}

