        if (inode_read_at(&dir, off, block, g_block_size) != 0) {
            break;
        }
        for (uint32_t p = 0; p + 8 < g_block_size && count < max_tests;) {
            struct ext4_dir_entry_2 *de = (struct ext4_dir_entry_2 *)(block + p);
            if (de->rec_len < 8) {
                break;
            }
            if (de->inode != 0 && de->file_type == EXT4_FT_REG_FILE &&
                !name_eq(de->name, de->name_len, ".") && !name_eq(de->name, de->name_len, "..")) {
                uint8_t magic[4];
                if (ext4_read_inode_prefix(de->inode, magic, sizeof(magic)) == 0 &&
                    memcmp(magic, "\x7f" "ELF", 4) == 0) {
                    copy_name(out[count].name, de->name, de->name_len);
                    out[count].ino = de->inode;
                    struct ext4_inode file_ino;
                    if (read_inode(de->inode, &file_ino) == 0) {
                        out[count].size = (uint32_t)inode_size(&file_ino);
                    } else {
                        out[count].size = 0;
                    }
                    count++;
                }
            }
            p += de->rec_len;
        }
    }
    sort_tests(out, count);
    return count;
}

