static int elf_is_valid(const uint8_t *elf, uint32_t size) {
    const struct elf64_ehdr *eh = (const struct elf64_ehdr *)elf;

    if (size < sizeof(*eh) || memcmp(eh->ident, "\x7f" "ELF", 4) != 0 || eh->ident[4] != 2) {
        return -1;
    }
    if (eh->phoff + (uint64_t)eh->phnum * eh->phentsize > size || eh->phentsize < sizeof(struct elf64_phdr)) {
        return -1;
    }
    return 0;
}

static int elf_interp_path(const uint8_t *elf, uint32_t size, char *out, size_t cap) {
    const struct elf64_ehdr *eh = (const struct elf64_ehdr *)elf;

    if (elf_is_valid(elf, size) != 0 || cap == 0) {
        return -1;
    }
    for (uint16_t i = 0; i < eh->phnum; i++) {
        const struct elf64_phdr *ph = (const struct elf64_phdr *)(elf + eh->phoff + i * eh->phentsize);
        if (ph->type != PT_INTERP) {
            continue;
        }
        if (ph->offset + ph->filesz > size || ph->filesz >= cap) {
            return -1;
        }
        memcpy(out, elf + ph->offset, ph->filesz);
        out[ph->filesz] = '\0';
        return 0;
    }
    return -1;
}

static int load_elf_image(uint64_t *root, const uint8_t *elf, uint32_t size, uint64_t load_bias,
                          uint64_t *entry, uint64_t *heap_end, uint64_t *phdr_addr,
                          uint64_t *phent, uint64_t *phnum) {
    const struct elf64_ehdr *eh = (const struct elf64_ehdr *)elf;
    uint64_t image_end = 0;
    uint64_t image_phdr = 0;

    if (elf_is_valid(elf, size) != 0) {
        return -1;
    }
    *entry = load_bias + eh->entry;
    *phent = eh->phentsize;
    *phnum = eh->phnum;
    for (uint16_t i = 0; i < eh->phnum; i++) {
        const struct elf64_phdr *ph = (const struct elf64_phdr *)(elf + eh->phoff + i * eh->phentsize);
        uint64_t seg_start;
        uint64_t seg_end;

        if (ph->type != PT_LOAD) {
            continue;
        }
        if (ph->filesz > ph->memsz || ph->offset + ph->filesz > size) {
            return -1;
        }
        seg_start = load_bias + ph->vaddr;
        seg_end = seg_start + ph->memsz;
        if (eh->phoff >= ph->offset &&
            eh->phoff + (uint64_t)eh->phnum * eh->phentsize <= ph->offset + ph->filesz) {
            image_phdr = seg_start + (eh->phoff - ph->offset);
        }
        uint64_t perm = PTE_R;
        if (ph->flags & 1) perm |= PTE_X;
        if (ph->flags & 2) perm |= PTE_W;
        if (ph->flags & 4) perm |= PTE_R;
        if (map_user_range(root, seg_start, seg_end, perm) != 0) {
            return -1;
        }
        copy_to_user(root, seg_start, elf + ph->offset, ph->filesz);
        if (seg_end > image_end) {
            image_end = seg_end;
        }
    }
    if (image_phdr == 0) {
        image_phdr = load_bias + eh->phoff;
    }
    *heap_end = align_up_u64(image_end, PAGE_SIZE);
    *phdr_addr = image_phdr;
    return 0;
}

static void resolve_loader_path(const char *in, const char *exec_name, char *out, size_t cap) {
    const char *lib_dir = g_current_lib_dir[0] ? g_current_lib_dir : "musl";

    if (str_contains(exec_name, "/glibc/")) {
        lib_dir = "glibc";
    } else if (str_contains(exec_name, "/musl/")) {
        lib_dir = "musl";
    }

    if (str_eq(in, "/lib/ld-musl-riscv64.so.1") || str_eq(in, "/lib/libc.so")) {
        copy_kernel_cstr(out, cap, "/musl/lib/libc.so");
    } else if (str_eq(in, "/lib/ld-linux-riscv64-lp64d.so.1") ||
               str_eq(in, "/lib/riscv64-linux-gnu/ld-linux-riscv64-lp64d.so.1")) {
        copy_kernel_cstr(out, cap, "/glibc/lib/ld-linux-riscv64-lp64d.so.1");
    } else if (str_eq(in, "/lib/riscv64-linux-gnu/tls/libc.so.6") ||
               str_eq(in, "/lib/libc.so.6") ||
               str_eq(in, "/lib/riscv64-linux-gnu/libc.so.6") ||
               str_eq(in, "/usr/lib/riscv64-linux-gnu/libc.so.6")) {
        copy_kernel_cstr(out, cap, "/glibc/lib/libc.so.6");
    } else if (str_eq(in, "/lib/libm.so.6") ||
               str_eq(in, "/lib/riscv64-linux-gnu/libm.so.6") ||
               str_eq(in, "/usr/lib/riscv64-linux-gnu/libm.so.6")) {
        copy_kernel_cstr(out, cap, "/glibc/lib/libm.so.6");
    } else if (str_eq(in, "libc.so")) {
        copy_kernel_cstr(out, cap, str_eq(lib_dir, "musl") ? "/musl/lib/libc.so" : "/glibc/lib/libc.so");
    } else if (str_eq(in, "libc.so.6")) {
        copy_kernel_cstr(out, cap, "/glibc/lib/libc.so.6");
    } else if (str_eq(in, "libm.so") || str_eq(in, "libm.so.6")) {
        copy_kernel_cstr(out, cap, "/glibc/lib/libm.so.6");
    } else if (str_eq(in, "ld-linux-riscv64-lp64d.so.1")) {
        copy_kernel_cstr(out, cap, "/glibc/lib/ld-linux-riscv64-lp64d.so.1");
    } else {
        copy_kernel_cstr(out, cap, in);
    }
}

