int user_write_file(const char *path, const char *data, int append) {
    char full[128];
    normalize_user_path((uint64_t)-100, path, full, sizeof(full));
    int idx = mem_file_create(full);
    size_t len = strlen(data);
    uint32_t off;

    if (idx < 0) {
        return -1;
    }
    off = append ? g_mem_files[idx].size : 0;
    if (off >= sizeof(g_mem_files[idx].data)) {
        return 0;
    }
    if (len > sizeof(g_mem_files[idx].data) - off) {
        len = sizeof(g_mem_files[idx].data) - off;
    }
    memcpy(g_mem_files[idx].data + off, data, len);
    g_mem_files[idx].size = off + (uint32_t)len;
    return (int)len;
}

