void compat_fill_stat(uint64_t ptr, uint64_t ino, uint32_t kind, uint32_t size) {
    if (!ptr) {
        return;
    }
    struct kstat_basic *st = (struct kstat_basic *)(uintptr_t)ptr;
    memset(st, 0, sizeof(*st));
    st->st_ino = ino;
    st->st_mode = (kind == FD_DIR || kind == FD_MEM_DIR) ? 0040755 : 0100644;
    st->st_nlink = 1;
    st->st_blksize = 512;
    st->st_size = size;
    st->st_blocks = (size + 511) / 512;
}

void compat_fill_stat_special(uint64_t ptr, uint64_t ino, uint32_t kind, uint32_t size,
                              uint32_t mode, uint64_t rdev) {
    struct kstat_basic *st;
    compat_fill_stat(ptr, ino, kind, size);
    if (!ptr) {
        return;
    }
    st = (struct kstat_basic *)(uintptr_t)ptr;
    if (mode) {
        st->st_mode = mode;
    }
    st->st_rdev = rdev;
}

void compat_fill_stat_owner(uint64_t ptr, uint64_t ino, uint32_t kind, uint32_t size,
                            uint32_t mode, uint64_t rdev, uint32_t uid, uint32_t gid) {
    struct kstat_basic *st;
    compat_fill_stat_special(ptr, ino, kind, size, mode, rdev);
    if (!ptr) {
        return;
    }
    st = (struct kstat_basic *)(uintptr_t)ptr;
    st->st_uid = uid;
    st->st_gid = gid;
}

void compat_fill_statx(uint64_t ptr, uint64_t ino, uint32_t kind, uint32_t size) {
    if (!ptr) {
        return;
    }
    struct statx_basic *st = (struct statx_basic *)(uintptr_t)ptr;
    memset(st, 0, sizeof(*st));
    st->stx_mask = 0x17ff;
    st->stx_blksize = 512;
    st->stx_nlink = 1;
    st->stx_uid = 0;
    st->stx_gid = 0;
    st->stx_mode = (kind == FD_DIR || kind == FD_MEM_DIR) ? 0040755 : 0100644;
    st->stx_ino = ino;
    st->stx_size = size;
    st->stx_blocks = (size + 511) / 512;
    st->stx_attributes_mask = 0;
    st->stx_dev_major = 8;
    st->stx_dev_minor = 0;
    st->stx_mnt_id = 1;
}

void compat_fill_statx_special(uint64_t ptr, uint64_t ino, uint32_t kind, uint32_t size,
                               uint32_t mode, uint64_t rdev) {
    struct statx_basic *st;
    uint32_t major;
    uint32_t minor;
    compat_fill_statx(ptr, ino, kind, size);
    if (!ptr) {
        return;
    }
    st = (struct statx_basic *)(uintptr_t)ptr;
    if (mode) {
        st->stx_mode = (uint16_t)mode;
    }
    major = (uint32_t)(((rdev >> 8) & 0xfff) | ((rdev >> 32) & ~0xfffULL));
    minor = (uint32_t)((rdev & 0xff) | ((rdev >> 12) & ~0xffULL));
    st->stx_rdev_major = major;
    st->stx_rdev_minor = minor;
}

void compat_fill_statx_owner(uint64_t ptr, uint64_t ino, uint32_t kind, uint32_t size,
                             uint32_t mode, uint64_t rdev, uint32_t uid, uint32_t gid) {
    struct statx_basic *st;
    compat_fill_statx_special(ptr, ino, kind, size, mode, rdev);
    if (!ptr) {
        return;
    }
    st = (struct statx_basic *)(uintptr_t)ptr;
    st->stx_uid = uid;
    st->stx_gid = gid;
}

void compat_fill_statfs(uint64_t ptr) {
    if (!ptr) {
        return;
    }
    struct statfs_basic *st = (struct statfs_basic *)(uintptr_t)ptr;
    memset(st, 0, sizeof(*st));
    st->f_type = 0xef53;
    st->f_bsize = 4096;
    st->f_blocks = 65536;
    st->f_bfree = 32768;
    st->f_bavail = 32768;
    st->f_files = 4096;
    st->f_ffree = 2048;
    st->f_namelen = 255;
    st->f_frsize = 4096;
}

void compat_fill_rlimit(uint64_t ptr) {
    if (!ptr) {
        return;
    }
    struct rlimit_basic *rl = (struct rlimit_basic *)(uintptr_t)ptr;
    rl->rlim_cur = 1024ULL * 1024ULL * 1024ULL;
    rl->rlim_max = 1024ULL * 1024ULL * 1024ULL;
}

