static void make_lib_path(char *dst, size_t cap, const char *lib_dir, const char *name) {
    size_t p = 0;
    if (cap == 0) {
        return;
    }
    dst[p++] = '/';
    for (size_t i = 0; lib_dir[i] && p + 1 < cap; i++) {
        dst[p++] = lib_dir[i];
    }
    if (lib_dir[0] && p + 1 < cap) {
        dst[p++] = '/';
    }
    for (size_t i = 0; name[i] && p + 1 < cap; i++) {
        dst[p++] = name[i];
    }
    dst[p] = '\0';
}

