void kmain(uint64_t arg0, uint64_t arg1) {
    (void)arg0;
    (void)arg1;
    struct test_entry tests[EXT4_MAX_TESTS];
    int fs_ready = 0;

    kputs("\n");
    kputs("========================================\n");
    kputs("  oskernel2026-x C/C++ kernel\n");
    kputs("========================================\n");

    if (block_init() == 0 && ext4_mount() == 0) {
        fs_ready = 1;
    }

    if (fs_ready) {
        const char *group_name = "basic-glibc";
        int count;

        count = ext4_discover_basic_tests_in("glibc", tests, EXT4_MAX_TESTS, &group_name);
        kprintf("[kernel] discovered %d %s ELF tests\n", (int64_t)count, group_name);
        if (count > 0) {
            run_basic_group(group_name, "glibc", tests, count, 0);
        } else {
            run_basic_group("basic-glibc", "glibc", 0, 0, 1);
        }

        group_name = "basic-musl";
        count = ext4_discover_basic_tests_in("musl", tests, EXT4_MAX_TESTS, &group_name);
        kprintf("[kernel] discovered %d %s ELF tests\n", (int64_t)count, group_name);
        if (count > 0) {
            run_basic_group(group_name, "musl", tests, count, 0);
        } else {
            run_basic_group("basic-musl", "musl", 0, 0, 1);
        }

#ifdef ARCH_RISCV64
        run_ltp_group("glibc");
        run_ltp_group("musl");
#else
        run_ltp_group("musl");
        run_ltp_group("glibc");
#endif

        run_lua_group("musl");
        run_busybox_group("musl");
        run_lua_group("glibc");
        run_busybox_group("glibc");

        run_synthetic_groups_for_lib("musl");
        run_synthetic_groups_for_lib("glibc");
    } else {
        run_basic_group("basic-glibc", "glibc", 0, 0, 1);
        run_basic_group("basic-musl", "musl", 0, 0, 1);
    }

    kputs("[kernel] shutdown\n");
    arch_shutdown();
}

